fn format_text(value: &str) -> String {
    if value.contains("|]") {
        format!("[{}]", value.replace(']', " ]"))
    } else if value.chars().any(|character| {
        matches!(
            character,
            '[' | ']' | '(' | ')' | '{' | '}' | ';' | '\n'
        )
    }) {
        format!("[|{}|]", value)
    } else {
        format!("[{value}]")
    }
}

